fun solve(nums: Array<Long>): Long {
    val sorted = nums.sortedWith(compareBy { it.abs() })
    var count = 0L
    for (i in 0 until sorted.size - 1) {
        val target = 2 * sorted[i].abs()
        var left = i + 1
        var right = sorted.size - 1
        var res = -1L
        while (left <= right) {
            val mid = (left + right) / 2
            val valMid = sorted[mid].abs()
            if (valMid <= target) {
                res = mid.toLong()
                left = mid + 1
            } else {
                right = mid - 1
            }
        }
        if (res != -1L) {
            count += res - i
        }
    }
    return count
}
